import{_ as t,o as e,c as a,a0 as n}from"./chunks/framework.jwovEGr5.js";const r="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",p=JSON.parse('{"title":"Log In & Out","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/logging-in.md","filePath":"getting-started/logging-in.md"}'),i={name:"getting-started/logging-in.md"};function s(g,o,l,u,h,d){return e(),a("div",null,[...o[0]||(o[0]=[n('<h1 id="log-in-out" tabindex="-1">Log In &amp; Out <a class="header-anchor" href="#log-in-out" aria-label="Permalink to &quot;Log In &amp; Out&quot;">​</a></h1><p>This guide covers signing in, what to do if the login screen stops accepting attempts, and signing out.</p><h2 id="logging-in" tabindex="-1">Logging in <a class="header-anchor" href="#logging-in" aria-label="Permalink to &quot;Logging in&quot;">​</a></h2><p><img src="'+r+'" alt="Login page"></p><ol><li>Open the app in your web browser.</li><li>On the login screen, enter your <strong>username</strong> and <strong>password</strong>.</li><li>Select <strong>Log in</strong>.</li></ol><p>If your details are correct, you land on your <a href="./dashboard-tour.html">dashboard</a>. What you see there depends on your <a href="./../roles/overview.html">role</a>.</p><h2 id="if-you-don-t-have-an-account-yet" tabindex="-1">If you don&#39;t have an account yet <a class="header-anchor" href="#if-you-don-t-have-an-account-yet" aria-label="Permalink to &quot;If you don&#39;t have an account yet&quot;">​</a></h2><p>You can&#39;t create your own account from the login screen alone — accounts are approved by an admin. See <strong><a href="./registering.html">Request an Account</a></strong>. If your kingdom doesn&#39;t allow self‑registration, ask your King or Alliance Leader to create your account for you.</p><h2 id="if-you-forgot-your-password" tabindex="-1">If you forgot your password <a class="header-anchor" href="#if-you-forgot-your-password" aria-label="Permalink to &quot;If you forgot your password&quot;">​</a></h2><p>Use <strong><a href="./forgot-password.html">Reset a Forgotten Password</a></strong>. There is no automatic &quot;reset link&quot; email — an admin approves your reset request.</p><h2 id="too-many-attempts-—-the-login-limit" tabindex="-1">&quot;Too many attempts&quot; — the login limit <a class="header-anchor" href="#too-many-attempts-—-the-login-limit" aria-label="Permalink to &quot;&quot;Too many attempts&quot; — the login limit&quot;">​</a></h2><p>For security, the login screen only allows a handful of tries in a short window. If you get the password wrong several times in a row, logins are <strong>temporarily blocked</strong> for a short cooldown period.</p><p>If this happens:</p><ul><li><strong>Wait</strong> a little while before trying again — the block lifts on its own.</li><li>Don&#39;t keep hammering the login button; repeated failures just extend the wait.</li><li>If you truly can&#39;t remember your password, use <a href="./forgot-password.html">Reset a Forgotten Password</a> instead of guessing.</li></ul><h2 id="logging-out" tabindex="-1">Logging out <a class="header-anchor" href="#logging-out" aria-label="Permalink to &quot;Logging out&quot;">​</a></h2><p>Select <strong>Logout</strong> in the top‑right corner of the app (next to your name). This ends your session on that device. Always log out on shared or public computers.</p><h2 id="trouble-getting-in" tabindex="-1">Trouble getting in? <a class="header-anchor" href="#trouble-getting-in" aria-label="Permalink to &quot;Trouble getting in?&quot;">​</a></h2><ul><li><strong>&quot;You don&#39;t have access&quot; after logging in</strong> — you&#39;re logged in fine, but your role doesn&#39;t allow that page. See <a href="./access-denied.html">&quot;You don&#39;t have access&quot;</a>.</li><li><strong>Account seems inactive or missing</strong> — your account may be waiting for approval or may have been disabled. Contact your King or Supreme Admin.</li></ul>',18)])])}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
